arguments.file_text:
#:property AllowUnsafeBlocks=true

Console.WriteLine($"nint size: {nint.Size} bytes");

Span<nint> span = stackalloc nint[5];
for (int i = 0; i < span.Length; i++)
    span[i] = (nint)(i * 10);

Console.WriteLine("stackalloc'd Span<nint>:");
foreach (var val in span)
    Console.Write($"  {val}");
Console.WriteLine();

Span<nuint> uspan = stackalloc nuint[3];
uspan[0] = 100;
uspan[1] = 200;
uspan[2] = 300;

Console.WriteLine("stackalloc'd Span<nuint>:");
foreach (var val in uspan)
    Console.Write($"  {val}");
Console.WriteLine();

